// // This module implements a 4-to-2 decoder with disable. Inputs are a 4-bit binary number a and a disable signal dis. Output is a 2-bit one-hot encoded signal y. If dis is 1, y should be 00. If dis is 0, y should be one-hot encoded based on the value of a.
module decoder2to4 (
    input [1:0] a,
    input en,
    output reg [3:0] y);

    always @(*) begin
        if (!en) y = 4'b0000;
        else case (a)
            2'b00: y = 4'b0001;
            2'b01: y = 4'b0010;
            2'b10: y = 4'b0100;
            2'b11: y = 4'b1000;
        endcase
    end
endmodule
